targets.expr:
node_filesystem_size_bytes{job="node", host=~"$vm", fstype!~"tmpfs|overlay|devtmpfs|nfs4?|cifs|fuse.*|squashfs"} - node_filesystem_avail_bytes{job="node", host=~"$vm", fstype!~"tmpfs|overlay|devtmpfs|nfs4?|cifs|fuse.*|squashfs"}
or label_replace(
  windows_logical_disk_size_bytes{job="windows", host=~"$vm", volume!~"HarddiskVolume.*|_Total"} - windows_logical_disk_free_bytes{job="windows", host=~"$vm", volume!~"HarddiskVolume.*|_Total"},
  "mountpoint", "$1", "volume", "(.+)"
)

node_filesystem_size_bytes{job="node", host=~"$vm", fstype!~"tmpfs|overlay|devtmpfs|nfs4?|cifs|fuse.*|squashfs"}
or label_replace(
  windows_logical_disk_size_bytes{job="windows", host=~"$vm", volume!~"HarddiskVolume.*|_Total"},
  "mountpoint", "$1", "volume", "(.+)"
)
